from typing import List
import sys

class Solution:
    def minimumValueSum(self, nums: List[int], andValues: List[int]) -> int:
        n = len(nums)
        m = len(andValues)
        INF = sys.maxsize

        # dp[i][j]: min sum to partition first i elements into j subarrays
        dp = [[INF] * (m + 1) for _ in range(n + 1)]
        dp[0][0] = 0  # base case: 0 elements, 0 subarrays

        for i in range(1, n + 1):
            for j in range(1, m + 1):
                # Try to extend the j-th subarray ending at i
                current_and = nums[i - 1]
                for k in range(i - 1, 0, -1):
                    current_and &= nums[k - 1]
                    if current_and == andValues[j - 1]:
                        dp[i][j] = min(dp[i][j], dp[k - 1][j - 1] + nums[i - 1])
                # Also consider the case where the j-th subarray is just [nums[i-1]]
                if nums[i - 1] == andValues[j - 1]:
                    dp[i][j] = min(dp[i][j], dp[i - 1][j - 1] + nums[i - 1])

        return dp[n][m] if dp[n][m] != INF else -1
